### JavaScript for Keyboard Navigation

```javascript
// Keyboard navigation handler for c-navigation
class NavigationKeyboardHandler {
  constructor(navElement) {
    this.nav = navElement;
    this.items = this.nav.querySelectorAll('.c-navigation__link, .c-navigation__toggle, .c-navigation__sublink');
    this.currentIndex = 0;
    this.init();
  }

  init() {
    this.nav.addEventListener('keydown', (e) => this.handleKeyDown(e));
    this.nav.addEventListener('click', (e) => this.handleClick(e));
  }

  handleKeyDown(e) {
    const items = Array.from(this.items);
    const currentItem = document.activeElement;
    const currentIndex = items.indexOf(currentItem);

    switch (e.key) {
      case 'ArrowDown':
        e.preventDefault();
        this.focusNextItem(currentIndex);
        break;

      case 'ArrowUp':
        e.preventDefault();
        this.focusPreviousItem(currentIndex);
        break;

      case 'ArrowRight':
        e.preventDefault();
        this.openSubmenu(currentItem);
        break;

      case 'ArrowLeft':
        e.preventDefault();
        this.closeSubmenu(currentItem);
        break;

      case 'Escape':
        e.preventDefault();
        this.closeAllSubmenus();
        this.focusParentItem(currentItem);
        break;

      case 'Home':
        e.preventDefault();
        this.focusFirstItem();
        break;

      case 'End':
        e.preventDefault();
        this.focusLastItem();
        break;

      case 'Enter':
      case ' ':
        if (currentItem.classList.contains('c-navigation__toggle')) {
          e.preventDefault();
          this.toggleSubmenu(currentItem);
        }
        break;
    }
  }

  handleClick(e) {
    const toggle = e.target.closest('.c-navigation__toggle');
    if (toggle) {
      this.toggleSubmenu(toggle);
    }
  }

  focusNextItem(currentIndex) {
    const nextIndex = (currentIndex + 1) % this.items.length;
    this.items[nextIndex].focus();
    this.items[nextIndex].tabIndex = 0;
    this.items[currentIndex].tabIndex = -1;
  }

  focusPreviousItem(currentIndex) {
    const prevIndex = (currentIndex - 1 + this.items.length) % this.items.length;
    this.items[prevIndex].focus();
    this.items[prevIndex].tabIndex = 0;
    this.items[currentIndex].tabIndex = -1;
  }

  openSubmenu(item) {
    const toggle = item.closest('.c-navigation__toggle');
    if (toggle) {
      toggle.setAttribute('aria-expanded', 'true');
      toggle.dataset.state = 'open';
      const submenu = document.getElementById(toggle.getAttribute('aria-controls'));
      if (submenu) {
        submenu.removeAttribute('hidden');
        const firstItem = submenu.querySelector('.c-navigation__sublink');
        if (firstItem) firstItem.focus();
      }
    }
  }

  closeSubmenu(item) {
    const submenu = item.closest('.c-navigation__submenu');
    if (submenu) {
      const toggle = this.nav.querySelector(`[aria-controls="${submenu.id}"]`);
      if (toggle) {
        toggle.setAttribute('aria-expanded', 'false');
        toggle.dataset.state = 'closed';
        submenu.setAttribute('hidden', '');
        toggle.focus();
      }
    }
  }

  toggleSubmenu(toggle) {
    const isExpanded = toggle.getAttribute('aria-expanded') === 'true';
    toggle.setAttribute('aria-expanded', !isExpanded);
    toggle.dataset.state = isExpanded ? 'closed' : 'open';
    const submenu = document.getElementById(toggle.getAttribute('aria-controls'));
    if (submenu) {
      submenu.toggleAttribute('hidden');
      if (!isExpanded) {
        const firstItem = submenu.querySelector('.c-navigation__sublink');
        if (firstItem) firstItem.focus();
      }
    }
  }

  closeAllSubmenus() {
    this.nav.querySelectorAll('.c-navigation__toggle').forEach(toggle => {
      toggle.setAttribute('aria-expanded', 'false');
      toggle.dataset.state = 'closed';
      const submenu = document.getElementById(toggle.getAttribute('aria-controls'));
      if (submenu) submenu.setAttribute('hidden', '');
    });
  }

  focusParentItem(currentItem) {
    const submenu = currentItem.closest('.c-navigation__submenu');
    if (submenu) {
      const toggle = this.nav.querySelector(`[aria-controls="${submenu.id}"]`);
      if (toggle) {
        toggle.focus();
        toggle.setAttribute('aria-expanded', 'false');
        toggle.dataset.state = 'closed';
        submenu.setAttribute('hidden', '');
      }
    }
  }

  focusFirstItem() {
    this.items[0].focus();
    this.items[0].tabIndex = 0;
    this.items.forEach((item, i) => {
      if (i !== 0) item.tabIndex = -1;
    });
  }

  focusLastItem() {
    const lastIndex = this.items.length - 1;
    this.items[lastIndex].focus();
    this.items[lastIndex].tabIndex = 0;
    this.items.forEach((item, i) => {
      if (i !== lastIndex) item.tabIndex = -1;
    });
  }
}

// Initialize on DOM ready
document.addEventListener('DOMContentLoaded', () => {
  document.querySelectorAll('.c-navigation').forEach(nav => {
    new NavigationKeyboardHandler(nav);
  });
});
```

## Design Decisions

1. **ARIA Roles and Labels**: Added `role="navigation"`, `role="menuitem"`, and `aria-label` to ensure screen readers properly identify navigation structure and purpose.

2. **`aria-current="page"`**: Applied to the active page link, providing clear context to assistive technologies about the current location.

3. **Keyboard Navigation**: Implemented full keyboard support with Arrow keys for navigation, Enter/Space for toggling submenus, and Escape for closing. The `tabindex` management ensures proper focus flow.

4. **Focus Management**: Used `:focus-visible` for keyboard-only focus indicators, preventing mouse users from seeing persistent focus rings. The JavaScript manages `tabindex` values to create a roving tabindex pattern.

5. **Submenu Accessibility**: Added `aria-expanded`, `aria-haspopup`, and `aria-controls` to toggle buttons, with `hidden` attribute on submenus for proper screen reader behavior.

6. **State Management**: Uses `data-state` for open/closed states alongside ARIA attributes, maintaining MCSS conventions while ensuring accessibility compliance.

# MCSS Dropdown Component Analysis

## Component Overview

The `c-dropdown` component is a **Molecule** in the MCSS taxonomy, composed of multiple atoms working together to create a toggleable menu interface.

## Complete Interaction Model

### 1. State Machine

```
                    ┌─────────────┐
                    │   Default   │
                    │  (closed)   │
                    └──────┬──────┘
                           │ click / Enter / Space
                           ▼
                    ┌─────────────┐
                    │    Open     │
                    │ data-state  │
                    │ ="open"     │
                    └──────┬──────┘
                           │ click outside / Escape / 
                           │ click option / Tab away
                           ▼
                    ┌─────────────┐
                    │   Default   │
                    │  (closed)   │
                    └─────────────┘
```

### 2. State Attributes

| Attribute | Values | Purpose |
|---|---|---|
| `data-state` | `"open"` / `"closed"` | Primary state indicator |
| `aria-expanded` | `"true"` / `"false"` | Accessibility state mirror |
| `data-mcs-triggers-event` | `"mcss:dropdown:toggled"` | Custom event emission |

### 3. Interaction Triggers

**Opening:**
- Click on trigger button
- `Enter` key on trigger (keyboard)
- `Space` key on trigger (keyboard)
- `ArrowDown` on trigger (keyboard)

**Closing:**
- Click outside dropdown (focus trap release)
- `Escape` key
- Selecting a menu option
- `Tab` away from dropdown
- Click on trigger again (toggle)

### 4. Event Flow

```
User Action → DOM Event → State Change → Attribute Update → Custom Event
                                                                  │
                                                                  ▼
                                                    mcss:dropdown:toggled
                                                    (detail: {state: "open"|"closed"})
```

