### 8. Focus Management

```javascript
// Focus trap implementation
function handleDropdownToggle(dropdown) {
  const isOpen = dropdown.dataset.state === 'open';
  const trigger = dropdown.querySelector('.c-dropdown__trigger');
  const menu = dropdown.querySelector('.c-dropdown__menu');
  const firstOption = menu.querySelector('[role="option"]');

  if (isOpen) {
    firstOption.focus();
    // Trap focus within menu
    menu.addEventListener('keydown', trapFocus);
  } else {
    trigger.focus();
    menu.removeEventListener('keydown', trapFocus);
  }
}
```

